INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5d2b9517-7b49-4602-b69f-0bb24675a354',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers.js — Providers, Signers, and Contract Interaction Without the Guesswork$escape$,
  $escape$ethers.js separates read and write concerns cleanly: a Provider handles chain reads (balances, calls, logs), while a Signer wraps a private key or wallet and can send transactions. A BrowserProvider bridges MetaMask into ethers v6, replacing the v5 Web3Provider. To interact with a contract, you attach either a Provider (read-only) or Signer (read-write) — the same ContractFactory handles both. For event listening, contract.on() uses a typed filter; always call contract.off() or contract.removeAllListeners() to avoid memory leaks in SPAs. One sharp edge: provider.getLogs() and contract.queryFilter() are distinct — queryFilter decodes log data using the ABI, getLogs returns raw RPC results. In v6, BigInt replaces ethers.BigNumber everywhere, so arithmetic is native JS. When switching networks, recreate the provider — stale providers silently query the wrong chain. Use provider.getNetwork() to assert chain ID before any sensitive write.$escape$,
  $escape$import { BrowserProvider, Contract, parseEther } from 'ethers';

const provider = new BrowserProvider(window.ethereum);
const signer = await provider.getSigner();

const contract = new Contract(ADDRESS, ABI, signer);

// Write
const tx = await contract.transfer(recipient, parseEther('1.0'));
await tx.wait();

// Read-only (no signer needed)
const readContract = new Contract(ADDRESS, ABI, provider);
const balance = await readContract.balanceOf(signer.address);

// Event listening
contract.on('Transfer', (from, to, value, event) => {
  console.log(`${from} → ${to}: ${value}`);
});

// Cleanup
contract.removeAllListeners('Transfer');$escape$,
  $escape$typescript$escape$,
