INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '95505409-a60c-4fd9-9ed6-4a0201becd6b',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers_js — Reading On-chain Data Without Wasting RPC Calls$escape$,
  $escape$ethers_js gives you multiple read primitives, but picking the wrong one wastes RPC quota fast. `provider.call()` maps directly to `eth_call` — use it for arbitrary calldata without ABI overhead, or to simulate state at a specific block by passing `{ blockTag: 12345678 }`. For event history, `contract.queryFilter(filter, fromBlock, toBlock)` wraps `eth_getLogs` with automatic ABI decoding — you get typed `EventLog` objects back, not raw hex. Build precise filters with `contract.filters.Transfer(null, recipientAddress)` to index only the second topic. Avoid open-ended `getLogs` calls without a block range; most RPC providers cap at 10k results or 2k blocks. For batching, ethers v6 doesn't expose `eth_call` multicall natively, but you can pair `provider.send('eth_call', [...])` with a Multicall3 contract or use `Promise.all()` on `contract.foo.staticCall()` calls — these coalesce into a single HTTP request when using `JsonRpcProvider` with its internal batch queue. Always set `blockTag: 'finalized'` for data you'll act on to avoid reorg surprises.$escape$,
  $escape$import { ethers } from 'ethers';

const provider = new ethers.JsonRpcProvider(process.env.RPC_URL);
const erc20 = new ethers.Contract(tokenAddress, ERC20_ABI, provider);

// Typed event logs via eth_getLogs
const filter = erc20.filters.Transfer(null, myAddress);
const logs = await erc20.queryFilter(filter, -10_000); // last 10k blocks

for (const log of logs) {
  const event = log as ethers.EventLog;
  console.log(event.args.from, event.args.value);
}

// eth_call at a specific block
const balance = await erc20.balanceOf(myAddress, { blockTag: 'finalized' });

// Batch reads with Promise.all (coalesced by JsonRpcProvider)
const [supply, decimals] = await Promise.all([
  erc20.totalSupply(),
  erc20.decimals(),
]);$escape$,
