INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a7cbd598-2540-45a8-818c-30be2750f654',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers_js ENS — Forward Resolution, Reverse Lookup, Avatars, and Text Records$escape$,
  $escape$ENS resolution in ethers.js v6 splits into two paths. `provider.resolveName("vitalik.eth")` returns the checksummed address, while `provider.lookupAddress(address)` reverses it — but ethers internally validates that the forward record matches the reverse claim, returning `null` if they diverge. This is a security check you'd have to implement manually with raw contract calls.

For richer profile data, call `provider.getResolver(name)` to get an `EnsResolver` instance. Its `getText(key)` method fetches arbitrary ENSIP-5 text records — standard keys include `"url"`, `"email"`, `"com.twitter"`, `"org.telegram"`, and `"description"`. The `getAvatar()` method goes further: it resolves the avatar record through multiple layers — plain URL, IPFS CID via a public gateway, and ERC-721/ERC-1155 NFT ownership verification — returning a resolved URL or `null`. Unlike v5's manual resolver calls, v6 coalesces multiple `getText` calls on the same resolver into a single multicall RPC round trip where supported.

Always null-check the resolver — unregistered names return `null` from `getResolver`, and calling methods on it will throw.$escape$,
  $escape$import { ethers } from "ethers";

const provider = new ethers.JsonRpcProvider(process.env.RPC_URL);

const address = await provider.resolveName("vitalik.eth");
// "0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045"

const reverseName = await provider.lookupAddress(address!);
// "vitalik.eth" — null if forward/reverse mismatch

const resolver = await provider.getResolver("vitalik.eth");
if (resolver) {
  const avatar  = await resolver.getAvatar();           // resolved URL or null
  const twitter = await resolver.getText("com.twitter");
  const email   = await resolver.getText("email");
  console.log({ address, reverseName, avatar, twitter, email });
}$escape$,
  $escape$typescript$escape$,
