INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8853f501-8b16-4780-9812-9bc5177101be',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers.js + IPFS Pinning — Wiring Pinata, NFT.Storage, and Self-Hosted Nodes Into Your Mint Flow$escape$,
  $escape$IPFS pinning services ensure your NFT metadata and assets stay permanently accessible — unpinned content gets garbage-collected by the network. In an ethers.js workflow, pinning sits upstream of your contract call: you pin first, receive a CID, then pass `ipfs://<CID>` as the `tokenURI` argument to your ERC-721 mint transaction.

**Pinata** is the most battle-tested option — POST JSON to `/pinning/pinJSONToIPFS` with a JWT and you get an `IpfsHash` back synchronously. **NFT.Storage** (now folded into Storacha/w3up) used CAR-file uploads via their SDK, offering free cold storage but slower retrieval. **web3.storage** follows the same w3up model.

**Self-hosted Kubo nodes** give you full control: pin via the HTTP API at `localhost:5001/api/v0/add`, but you're responsible for uptime and replication.

For production dApps, always store `ipfs://` URIs on-chain — never a gateway URL — so the metadata stays gateway-agnostic. Use Pinata's dedicated gateways (`gateway.pinata.cloud`) at read-time to avoid public gateway throttling when your ethers.js frontend batch-resolves `tokenURI()` calls across hundreds of NFTs.$escape$,
  $escape$import { ethers } from "ethers";
import axios from "axios";

async function pinAndMint(metadata: object, contractAddress: string) {
  const { data } = await axios.post(
    "https://api.pinata.cloud/pinning/pinJSONToIPFS",
    metadata,
    { headers: { Authorization: `Bearer ${process.env.PINATA_JWT}` } }
  );
  const tokenURI = `ipfs://${data.IpfsHash}`;

  const provider = new ethers.BrowserProvider(window.ethereum);
  const signer = await provider.getSigner();
  const nft = new ethers.Contract(
    contractAddress,
    ["function mint(address to, string uri) returns (uint256)"],
    signer
  );

  const tx = await nft.mint(await signer.getAddress(), tokenURI);
  return tx.wait();
}$escape$,
