INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd18beca0-aa9e-4f93-9d93-f0a7ea2131e8',
  '00000000-0000-0000-0000-000000000001',
  $escape$ethers.js Contract ABIs — Encoding, Decoding, and Typed Interfaces$escape$,
  $escape$An ABI (Application Binary Interface) is the contract between your JavaScript code and a deployed Solidity contract — it defines function signatures, parameter types, and return types in a JSON schema that ethers.js uses to encode calldata and decode responses.

When you call a contract function, ethers.js uses the ABI to ABI-encode arguments into the 4-byte function selector + padded hex payload. On return, it decodes the raw bytes back into typed JS values. This happens automatically via `Contract` instances.

The `Interface` class is the core primitive. You can use it standalone to encode/decode without a provider — useful for transaction introspection or building raw calldata. `interface.encodeFunctionData('transfer', [to, amount])` produces the hex payload; `interface.decodeFunctionResult('balanceOf', resultBytes)` unpacks the response.

For type safety, use `typechain` or `@typechain/ethers-v6` to generate TypeScript wrappers from your ABI JSON. This gives you fully-typed `Contract` instances where `contract.transfer(to, amount)` is statically checked at compile time — no more silent argument mismatches.$escape$,
  $escape$import { Interface, Contract, JsonRpcProvider } from 'ethers';

const abi = [
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
];

// Standalone Interface — no provider needed
const iface = new Interface(abi);
const calldata = iface.encodeFunctionData('transfer', [
  '0xRecipient...',
  1000n,
]);
console.log(calldata); // 0xa9059cbb...

// Decode raw result bytes
const rawResult = '0x0000...0001';
const [success] = iface.decodeFunctionResult('transfer', rawResult);

// Full contract instance — encoding/decoding is automatic
const provider = new JsonRpcProvider(process.env.RPC_URL);
const token = new Contract('0xToken...', abi, provider);
const balance = await token.balanceOf('0xOwner...');$escape$,
  $escape$typescript$escape$,
